import { useCallback, useEffect, useState } from 'react';
import {
  PlaidLinkOnEvent,
  PlaidLinkOnExit,
  PlaidLinkOnSuccess,
  PlaidLinkOptions,
  usePlaidLink,
} from 'react-plaid-link';
import { IErrorResponse } from '@domain/error';
import { useCreatePlaidIdvLinkToken, useCreatePlaidLinkToken } from '@state/public/plaid';

type Params = {
  onEvent?: PlaidLinkOnEvent;
  onExit?: PlaidLinkOnExit;
  onSuccess?: PlaidLinkOnSuccess;
  onTokenFetchError?: (error: IErrorResponse | unknown) => void;
};

export const usePlaidIdv = ({ onEvent, onExit, onSuccess, onTokenFetchError }: Params) => {
  const [token, setToken] = useState<string | null>(null);

  const { createPlaidIdvLinkToken } = useCreatePlaidIdvLinkToken({
    onError: onTokenFetchError,
  });

  useEffect(() => {
    const fetchPlaidLinkToken = async () => {
      try {
        const { token: linkToken } = await createPlaidIdvLinkToken();
        setToken(linkToken);
      } catch (e) {
        onTokenFetchError?.(e);
      }
    };
    fetchPlaidLinkToken();
  }, [createPlaidIdvLinkToken, onTokenFetchError]);

  const handleOnSuccess = useCallback<PlaidLinkOnSuccess>(
    (publicToken, metadata) => onSuccess?.(publicToken, metadata),
    [onSuccess]
  );

  const handleOnEvent = useCallback<PlaidLinkOnEvent>(
    (eventName, metadata) => onEvent?.(eventName, metadata),
    [onEvent]
  );

  const handleOnExit = useCallback<PlaidLinkOnExit>(
    (error, metadata) => onExit?.(error, metadata),
    [onExit]
  );

  // if we're using the token we shouldn't need to pass any of the other stuff
  const config: PlaidLinkOptions = {
    onEvent: handleOnEvent,
    onExit: handleOnExit,
    onSuccess: handleOnSuccess,
    token,
  };

  const { error, exit, open, ready } = usePlaidLink(config);

  return {
    error,
    exit,
    open,
    ready,
    token,
  };
};

export const usePlaid = ({ onEvent, onExit, onSuccess }: Params = {}) => {
  const [token, setToken] = useState<string | null>(null);
  const { createPlaidLinkToken } = useCreatePlaidLinkToken();

  useEffect(() => {
    createPlaidLinkToken()
      .then(({ token: linkToken }) => setToken(linkToken))
      .catch((error) => console.error(error));
  }, [createPlaidLinkToken]);

  const handleOnSuccess = useCallback<PlaidLinkOnSuccess>(
    (publicToken, metadata) => onSuccess?.(publicToken, metadata),
    [onSuccess]
  );

  const handleOnEvent = useCallback<PlaidLinkOnEvent>(
    (eventName, metadata) => onEvent?.(eventName, metadata),
    [onEvent]
  );

  const handleOnExit = useCallback<PlaidLinkOnExit>(
    (error, metadata) => onExit?.(error, metadata),
    [onExit]
  );

  const config: PlaidLinkOptions = {
    accountSubtypes: {
      depository: ['DepositoryAccountSubtype.Checking, DepositoryAccountSubtype.Savings'],
    },
    clientName: process.env.VITE_PLAID_CLIENT_ID || '',
    env: process.env.VITE_PLAID_ENVIRONMENT || 'development',
    onEvent: handleOnEvent,
    onExit: handleOnExit,
    onSuccess: handleOnSuccess,
    product: ['auth', 'transactions'],
    publicKey: process.env.VITE_PLAID_PUBLIC_KEY || '',
    token,
  };

  const { error, exit, open, ready } = usePlaidLink(config);

  return {
    error,
    exit,
    open,
    ready,
    token,
  };
};
