import { useMutation } from 'react-query';
import { IErrorResponse } from '@domain/error';
import { ApiClient } from '@service/anedot/client';

type Response = {
  token: string;
};

export const useCreatePlaidIdvLinkToken = ({
  onError,
}: { onError?: (error: IErrorResponse) => void } = {}) => {
  const { mutateAsync: createPlaidIdvLinkToken } = useMutation<Response, IErrorResponse, void>(
    () => {
      // todo: send address and other info that we've collected via the form
      //  if available
      return new ApiClient({ namespace: 'public' }).post<void, Response>(
        `/plaid_link_tokens/identity`
      );
    },
    {
      onError: (error) => {
        onError?.(error);
      },
    }
  );

  return { createPlaidIdvLinkToken };
};
