import { useQuery } from 'react-query';
import { VolumeResponse } from '@domain/reports/volume';
import { ApiClient } from '@service/anedot/client';
import { useGetAccount } from '@state/accounts';
import { generateQueryKey, resourceKeys } from '@state/cacheHelper';
import { serializeDate } from '@ui/components/filters/serde';
import { makeSearchParams } from '@utils';
import { TaskQueue } from '@utils/taskQueue';
import { SIXTY_MINUTES } from './constants';

type Params = {
  accountId?: string;
  interval: 'week' | 'month' | 'quarter';
  intervalCount?: number;
  queue?: TaskQueue<VolumeResponse>;
  refetchInterval?: number;
  staleTime?: number;
  startDate: Date;
};

export const useGetVolume = ({
  accountId,
  interval,
  intervalCount = 1,
  queue,
  refetchInterval = SIXTY_MINUTES,
  staleTime = SIXTY_MINUTES,
  startDate,
}: Params) => {
  const { currentAccount } = useGetAccount();
  const accountIdParam = accountId || currentAccount?.id;

  const params = makeSearchParams({
    account_id: accountIdParam,
    interval,
    interval_count: intervalCount,
    start_date: serializeDate(startDate),
  });

  const query = useQuery<VolumeResponse, string>(
    generateQueryKey({
      accountId,
      parameters: params.raw,
      resourceKey: resourceKeys.reportsVolume,
    }),
    async ({ signal }) => {
      const task = () =>
        new ApiClient().get<VolumeResponse>(`accounts/reports/volume?${params.toString()}`, {
          signal,
        });

      return queue ? queue.enqueue(task) : task();
    },
    {
      enabled: !!accountIdParam,
      keepPreviousData: true,
      refetchInterval,
      staleTime,
    }
  );

  return {
    intervals: query.data?.intervals,
    isFetched: query.isFetched,
    isLoading: query.isLoading,
  };
};
