  shouldShowToast = true,
  userId,
}: Params) => {
  const { t } = useTranslation('settings', { keyPrefix: 'users.permissions.state' });
  const { currentAccount } = useGetAccount();
  const accountId = currentAccount?.id;

  const { refreshCache } = useCacheHelper(resourceKeys.org.users);
  const { refreshCache: refreshCampaigns } = useCacheHelper(resourceKeys.campaigns);

  const { showToast } = useToast();
  const { setUser } = useAuthStore();

  const { isLoading: isUpdatingUserAccess, mutate: updateUserAccess } = useMutation(
    ({ ...user }: UpdateUserAccessParams) => {
      if (!accountId) {
        throw new Error('an account must be selected!');
      }
      if (!userId) {
        throw new Error('a user must be selected!');
      }

      return new ApiClient().put<UpdateOrgUser, OrgUser>(`/users/${userId}`, {
        ...user,
        accountId,
      });
    },
    {
      onError: () => {
        if (shouldShowToast || shouldShowErrorToast) {
          showToast({
            message: t('updateFailure'),
            variant: 'error',
          });
        }
      },

      onSuccess: async (user) => {
        await Promise.all([refreshCache(user.id), refreshCampaigns(user.id)]);

        if (shouldShowToast || shouldShowSuccessToast) {
          showToast({
            message: t('updateSuccess'),
            variant: 'success',
          });
        }
      },
    }
  );

  const {
    isLoading: isUpdatingUserDetails,
    mutate: updateUserDetails,
    mutateAsync: updateUserDetailsAsync,
  } = useMutation(
    (details: UpdateUserDetailsParams) => {
      if (!accountId) {
        throw new Error('an account must be selected!');
      }
      if (!userId) {
        throw new Error('a user must be selected!');
      }

      return new ApiClient({ namespace: 'user' }).put<UpdateUserDetailsParams, IUser>(
        `/me`,
        details
      );
    },
    {
      onError: () => {
        if (shouldShowToast || shouldShowErrorToast) {
          showToast({
            message: t('updateFailure'),
            variant: 'error',
          });
        }
      },

      onSuccess: (updatedUser) => {
        setUser(updatedUser);

        if (shouldShowToast || shouldShowSuccessToast) {
          showToast({
            message: t('updateSuccess'),
            variant: 'success',
          });
        }
      },
    }
  );

  return {
    isLoading: isUpdatingUserAccess || isUpdatingUserDetails,
    updateUserAccess,
    updateUserDetails,
    updateUserDetailsAsync,
  };
};
